components.codeTemplate:
Menu {
    Button("Duplicate", systemImage: "plus.square.on.square") { }
    Button("Rename", systemImage: "pencil") { }
    Menu("Copy") {
        Button("Copy") { }
        Button("Copy Path") { }
    }
    Section {
        Button("Delete", role: .destructive) { }
    }
} label: {
    Label("{title}", systemImage: "{systemImage}")
} primaryAction: {
    // primary action when hasPrimaryAction
}
.menuStyle(.{menuStyle})
.menuOrder(.{menuOrder})
.menuIndicator(.{menuIndicator})
.controlSize(.{controlSize})
.disabled({isDisabled})

NavigationStack {
    List {
        ForEach(items, id: \.self) { Text($0) }
            .onDelete { items.remove(atOffsets: $0) }
            .onMove { items.move(fromOffsets: $0, toOffset: $1) }
    }
    .toolbar {
        ToolbarItem(placement: .{placement}) {
            EditButton()
                .disabled({isDisabled})
        }
    }
}

ControlGroup {
    Button("Media", systemImage: "photo") { }
    Button("Chart", systemImage: "chart.bar") { }
    Button("Graph", systemImage: "point.topleft.down.curvedto.point.bottomright.up") { }
} label: {
    Label("{label}", systemImage: "plus")
}
.controlGroupStyle(.{controlGroupStyle})
.controlSize(.{controlSize})
.tint({tint})
.disabled({isDisabled})

ShareLink(item: {item}, subject: Text("{subject}"), message: Text("{message}")) {
    Label("{label}", systemImage: "square.and.arrow.up")
}
.buttonStyle(.{style})
.disabled({isDisabled})

TextFieldLink(prompt: Text("{prompt}")) {
    Text("{label}")
} onSubmit: { text in
    // handle entered text
}
.disabled({isDisabled})
